+	// Verify source data arrived in clone
+	for i := 1; i <= 3; i++ {
+		id := fmt.Sprintf("rt-src-%03d", i)
+		issue, getErr := cloneStore.GetIssue(ctx, id)
+		if getErr != nil {
+			t.Fatalf("clone GetIssue(%s) failed: %v", id, getErr)
+		}
